/* ══════════ INTRO — drift through the rain toward the sign ══════════ */
(function () {
  const LOGO_DATA = 'data:image/png;base64,';
  const intro = document.getElementById('intro');
  const enterBtn = document.getElementById('introEnter');
  const statusEl = document.getElementById('introStatus');
  const pctEl = document.getElementById('introPct');
  const canvas = document.getElementById('intro3d');

  const reduced = window.matchMedia('(prefers-reduced-motion: reduce)').matches;

  let flyStart = 0; // fly-through: the sign rushes at you before the cut
  function finish() {
    if (introDone) return;
    introDone = true;
    stopAmbient(true);
    flyStart = performance.now();
    setTimeout(() => {
      intro.classList.add('eject');
      setTimeout(() => {
        intro.classList.add('gone');
        document.dispatchEvent(new CustomEvent('intro:done'));
        setTimeout(() => intro.remove(), 700);
      }, 380);
    }, 640);
  }

  /* ── neutral ambient while loading: night rain + soft pad, all synthesized ── */
  const soundBtn = document.getElementById('introSound');
  let ambient = null, introDone = false;
  let ambientOn = localStorage.getItem('ltd-ambient') !== 'off';
  function updateSoundBtn() {
    if (!soundBtn) return;
    soundBtn.textContent = ambientOn ? '♪ SOUND ON' : '♪ SOUND OFF';
    soundBtn.classList.toggle('off', !ambientOn);
  }
  function startAmbient() {
    if (ambient || !ambientOn || introDone) return;
    try {
      const ac = new (window.AudioContext || window.webkitAudioContext)();
      if (ac.state === 'suspended') { ac.close(); return; } // no gesture yet — retry later
      const master = ac.createGain();
      master.gain.setValueAtTime(0.0001, ac.currentTime);
      master.gain.linearRampToValueAtTime(0.14, ac.currentTime + 2.5); // soft fade in
      master.connect(ac.destination);

      // rain: looped brown-ish noise through a low shelf
      const len = ac.sampleRate * 2;
      const buf = ac.createBuffer(1, len, ac.sampleRate);
      const d = buf.getChannelData(0);
      let lastV = 0;
      for (let i = 0; i < len; i++) {
        const w = Math.random() * 2 - 1;
        lastV = (lastV + 0.02 * w) / 1.02;
        d[i] = lastV * 1.8 + w * 0.16;
      }
      const src = ac.createBufferSource();
      src.buffer = buf; src.loop = true;
      const lp = ac.createBiquadFilter(); lp.type = 'lowpass'; lp.frequency.value = 1100;
      const rainGain = ac.createGain(); rainGain.gain.value = 0.6;
      src.connect(lp).connect(rainGain).connect(master);
      src.start();

      // pad: detuned triangle chord breathing very slowly (Am add9 colour)
      [110, 164.81, 246.94].forEach((f, i) => {
        const o = ac.createOscillator();
        o.type = 'triangle'; o.frequency.value = f; o.detune.value = (i - 1) * 5;
        const og = ac.createGain(); og.gain.value = 0.05;
        const lfo = ac.createOscillator(); lfo.frequency.value = 0.05 + i * 0.021;
        const lg = ac.createGain(); lg.gain.value = 0.028;
        lfo.connect(lg).connect(og.gain); lfo.start();
        o.connect(og).connect(master); o.start();
      });

      ambient = { ac, master };
    } catch (e) { /* no audio — fine */ }
  }
  function stopAmbient(fade) {
    if (!ambient) return;
    const { ac, master } = ambient;
    ambient = null;
    try {
      master.gain.cancelScheduledValues(ac.currentTime);
      master.gain.setValueAtTime(Math.max(master.gain.value, 0.0001), ac.currentTime);
      master.gain.linearRampToValueAtTime(0.0001, ac.currentTime + (fade ? 1.1 : 0.15));
      setTimeout(() => { try { ac.close(); } catch (e) {} }, fade ? 1300 : 250);
    } catch (e) {}
  }
  if (soundBtn) {
    updateSoundBtn();
    soundBtn.addEventListener('click', e => {
      e.stopPropagation();
      ambientOn = !ambientOn;
      localStorage.setItem('ltd-ambient', ambientOn ? 'on' : 'off');
      updateSoundBtn();
      if (ambientOn) startAmbient(); else stopAmbient(false);
    });
  }
  // browsers unlock audio only after a gesture — catch the very first one
  ['pointerdown', 'keydown', 'touchstart', 'wheel', 'pointermove'].forEach(ev =>
    window.addEventListener(ev, () => startAmbient(), { once: true, capture: true, passive: true }));
  startAmbient(); // works right away if the tab already had a gesture

  if (!window.THREE || reduced) { // graceful skip
    if (soundBtn) soundBtn.remove();
    stopAmbient(false);
    intro.classList.add('gone');
    document.dispatchEvent(new CustomEvent('intro:done'));
    setTimeout(() => intro.remove(), 600);
    return;
  }

  /* --- scene --- */
  let renderer;
  try {
    renderer = new THREE.WebGLRenderer({ canvas, antialias: true, alpha: false });
  } catch (e) { // no WebGL — skip gracefully
    intro.classList.add('gone');
    document.dispatchEvent(new CustomEvent('intro:done'));
    setTimeout(() => intro.remove(), 600);
    return;
  }
  renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
  const scene = new THREE.Scene();
  scene.background = new THREE.Color(0x050409);
  scene.fog = new THREE.FogExp2(0x0a0714, 0.055);

  const camera = new THREE.PerspectiveCamera(60, 1, 0.1, 200);
  camera.position.set(0, 0.4, 30);

  function size() {
    renderer.setSize(innerWidth, innerHeight, false);
    camera.aspect = innerWidth / innerHeight;
    camera.updateProjectionMatrix();
  }
  size();
  addEventListener('resize', size);

  /* neon sign — the real logo drawn to a canvas with glow */
  function signTexture(logoImg) {
    const c = document.createElement('canvas');
    c.width = 1024; c.height = 512;
    const x = c.getContext('2d');
    x.clearRect(0, 0, c.width, c.height);
    if (logoImg) {
      // fit logo into the frame, keep proportions
      const maxW = 660, maxH = 400;
      const s = Math.min(maxW / logoImg.width, maxH / logoImg.height);
      const w = logoImg.width * s, h = logoImg.height * s;
      const dx = (1024 - w) / 2, dy = (430 - h) / 2;
      const glow = (blur, alpha) => {
        x.shadowColor = 'rgba(255,92,138,1)'; x.shadowBlur = blur; x.globalAlpha = alpha;
        x.drawImage(logoImg, dx, dy, w, h);
      };
      glow(120, .7); glow(80, .9); glow(36, .95); glow(10, 1); glow(0, 1);
    } else {
      x.textAlign = 'center';
      x.font = '800 130px "Shippori Mincho B1", serif';
      x.shadowColor = 'rgba(255,92,138,1)'; x.shadowBlur = 40; x.globalAlpha = .95;
      x.fillStyle = '#fff';
      x.fillText('Lunchtime', 512, 205);
      x.fillStyle = '#ffd7e2';
      x.fillText('Dead', 512, 360);
    }
    // kana strip
    x.textAlign = 'center';
    x.shadowBlur = 18; x.shadowColor = 'rgba(156,198,201,.9)';
    x.fillStyle = '#9cc6c9'; x.globalAlpha = 1;
    x.font = '28px "DotGothic16", monospace';
    x.fillText('ラ ン チ タ イ ム ・ デ ッ ド', 512, 470);
    return new THREE.CanvasTexture(c);
  }

  const signMat = new THREE.MeshBasicMaterial({
    map: signTexture(null), transparent: true, depthWrite: false,
    blending: THREE.AdditiveBlending
  });
  // swap in the real logo as soon as it decodes
  const logoImg = new Image();
  logoImg.onload = () => { signMat.map = signTexture(logoImg); refl.material.map = signMat.map; };
  logoImg.src = LOGO_DATA; // embedded: avoids canvas tainting on file://
  const sign = new THREE.Mesh(new THREE.PlaneGeometry(12, 6), signMat);
  sign.position.set(0, 0.6, -6);
  scene.add(sign);

  // halo behind the sign
  const haloTex = (() => {
    const c = document.createElement('canvas'); c.width = c.height = 256;
    const x = c.getContext('2d');
    const g = x.createRadialGradient(128, 128, 10, 128, 128, 128);
    g.addColorStop(0, 'rgba(255,92,138,.55)');
    g.addColorStop(.5, 'rgba(255,92,138,.16)');
    g.addColorStop(1, 'rgba(255,92,138,0)');
    x.fillStyle = g; x.fillRect(0, 0, 256, 256);
    return new THREE.CanvasTexture(c);
  })();
  const halo = new THREE.Sprite(new THREE.SpriteMaterial({ map: haloTex, transparent: true, depthWrite: false }));
  halo.scale.set(26, 15, 1);
  halo.position.copy(sign.position).z -= 0.5;
  scene.add(halo);

  /* wet street reflection hint */
  const floorMat = new THREE.MeshBasicMaterial({ color: 0x050409 });
  const floor = new THREE.Mesh(new THREE.PlaneGeometry(300, 300), floorMat);
  floor.rotation.x = -Math.PI / 2; floor.position.y = -3.2;
  scene.add(floor);
  const refl = new THREE.Mesh(new THREE.PlaneGeometry(12, 6), new THREE.MeshBasicMaterial({
    map: signMat.map, transparent: true, opacity: 0.16, depthWrite: false
  }));
  refl.rotation.x = -Math.PI / 2;
  refl.position.set(0, -3.15, -3.4);
  scene.add(refl);

  /* ── real 3D logo: extruded from the vector .ai contours ── */
  let sign3d = null, sign3dMats = null, kanaPlane = null;
  function kanaTexture() {
    const c = document.createElement('canvas');
    c.width = 1024; c.height = 128;
    const x = c.getContext('2d');
    x.textAlign = 'center';
    x.font = '34px "DotGothic16", monospace';
    x.shadowColor = 'rgba(156,198,201,.95)'; x.shadowBlur = 18;
    x.fillStyle = '#9cc6c9';
    x.fillText('ラ ン チ タ イ ム ・ デ ッ ド', 512, 78);
    return new THREE.CanvasTexture(c);
  }
  (function build3D() {
    try {
      if (!window.LTD_LOGO_SVG || !THREE.SVGLoader) return;
      const data = new THREE.SVGLoader().parse(window.LTD_LOGO_SVG);
      const shapes = [], holePts = [];
      data.paths.forEach(p => {
        const fill = String((p.userData.style || {}).fill || '').toLowerCase();
        const isWhite = fill.includes('100%') || fill === '#ffffff' || fill === '#fff' || fill === 'white' || fill.includes('255');
        if (isWhite) p.subPaths.forEach(sp => holePts.push(sp.getPoints(24)));
        else THREE.SVGLoader.createShapes(p).forEach(s => shapes.push(s));
      });
      // white overlay shapes are letter counters → become real holes
      holePts.forEach(pts => {
        const c = new THREE.Box2().setFromPoints(pts).getCenter(new THREE.Vector2());
        for (const s of shapes) {
          const sp = s.getPoints(24);
          if (new THREE.Box2().setFromPoints(sp).containsPoint(c)) {
            const rev = THREE.ShapeUtils.isClockWise(sp) === THREE.ShapeUtils.isClockWise(pts) ? pts.slice().reverse() : pts;
            s.holes.push(new THREE.Path(rev));
            break;
          }
        }
      });
      if (!shapes.length) return;
      const geo = new THREE.ExtrudeGeometry(shapes, {
        depth: 90, bevelEnabled: true, bevelThickness: 10, bevelSize: 8,
        bevelSegments: 2, curveSegments: 10
      });
      geo.computeBoundingBox();
      const size = new THREE.Vector3();
      geo.boundingBox.getSize(size);
      const ctr = geo.boundingBox.getCenter(new THREE.Vector3());
      geo.translate(-ctr.x, -ctr.y, -ctr.z);
      sign3dMats = [
        new THREE.MeshBasicMaterial({ color: 0xfff1f6, transparent: true, side: THREE.DoubleSide }), // tube faces
        new THREE.MeshBasicMaterial({ color: 0xff4f83, transparent: true, side: THREE.DoubleSide })  // depth walls
      ];
      sign3d = new THREE.Mesh(geo, sign3dMats);
      const k = 7.4 / size.x;
      sign3d.scale.set(k, -k, k); // svg is y-down
      sign3d.position.set(0, 1.1, -6);
      scene.add(sign3d);
      sign.visible = false; // flat billboard replaced by the real thing
      // kana strip keeps living under the 3D sign
      kanaPlane = new THREE.Mesh(
        new THREE.PlaneGeometry(9, 1.12),
        new THREE.MeshBasicMaterial({ map: kanaTexture(), transparent: true, depthWrite: false })
      );
      kanaPlane.position.set(0, -2.85, -5.9);
      scene.add(kanaPlane);
      if (document.fonts) document.fonts.ready.then(() => {
        if (kanaPlane) kanaPlane.material.map = kanaTexture();
      });
    } catch (e) { /* flat sign remains as fallback */ }
  })();

  /* rain — falling line points */
  const RAIN = 1600;
  const rainGeo = new THREE.BufferGeometry();
  const pos = new Float32Array(RAIN * 3);
  for (let i = 0; i < RAIN; i++) {
    pos[i * 3] = (Math.random() - 0.5) * 60;
    pos[i * 3 + 1] = Math.random() * 30 - 4;
    pos[i * 3 + 2] = Math.random() * 50 - 20;
  }
  rainGeo.setAttribute('position', new THREE.BufferAttribute(pos, 3));
  const rain = new THREE.Points(rainGeo, new THREE.PointsMaterial({
    color: 0x9cc6c9, size: 0.05, transparent: true, opacity: 0.55
  }));
  scene.add(rain);

  /* floating dust / bokeh */
  const DUST = 220;
  const dustGeo = new THREE.BufferGeometry();
  const dpos = new Float32Array(DUST * 3);
  for (let i = 0; i < DUST; i++) {
    dpos[i * 3] = (Math.random() - 0.5) * 40;
    dpos[i * 3 + 1] = Math.random() * 12 - 3;
    dpos[i * 3 + 2] = Math.random() * 40 - 15;
  }
  dustGeo.setAttribute('position', new THREE.BufferAttribute(dpos, 3));
  const dust = new THREE.Points(dustGeo, new THREE.PointsMaterial({
    map: haloTex, color: 0xffffff, size: 0.55, transparent: true, opacity: 0.16, depthWrite: false
  }));
  scene.add(dust);

  /* --- progress: wait for fonts + first paint, minimum cinematic time --- */
  let progress = 0, target = 0, ready = false, entered = false;
  const t0 = performance.now();
  Promise.all([
    document.fonts ? document.fonts.ready : Promise.resolve(),
    new Promise(r => setTimeout(r, 2200))
  ]).then(() => { target = 100; });

  // refresh texture once real fonts are in (kana strip)
  if (document.fonts) document.fonts.ready.then(() => {
    signMat.map = signTexture(logoImg.complete && logoImg.naturalWidth ? logoImg : null);
    refl.material.map = signMat.map;
  });

  enterBtn.addEventListener('click', e => { e.stopPropagation(); if (!entered) { entered = true; finish(); } });
  // once ready, a tap anywhere lets the visitor in
  intro.addEventListener('click', () => { if (ready && !entered) { entered = true; finish(); } });
  // safety: never trap the visitor
  setTimeout(() => { if (!ready) { target = 100; } }, 9000);

  /* --- loop --- */
  let raf;
  function loop(now) {
    raf = requestAnimationFrame(loop);
    const t = (now - t0) / 1000;

    target = Math.max(target, Math.min(96, t * 34)); // trickle
    progress += (target - progress) * 0.05;
    pctEl.textContent = Math.round(progress) + '%';

    if (progress > 99 && !ready) {
      ready = true;
      statusEl.textContent = 'PLAY';
      enterBtn.classList.add('ready');
    }

    // camera: slow dolly toward the sign + gentle sway
    const dolly = Math.min(10.5, t * 1.15);
    camera.position.z = 30 - dolly - Math.min(6, progress / 18);
    camera.position.x = Math.sin(t * 0.35) * 0.55;
    camera.position.y = 0.4 + Math.sin(t * 0.22) * 0.25;
    if (flyStart) {
      // accelerating rush straight into the neon
      const fp = Math.min(1, (now - flyStart) / 640);
      const e = fp * fp * fp;
      camera.position.z += (-4.55 - camera.position.z) * e;
      camera.position.x *= 1 - e;
      camera.position.y += (0.9 - camera.position.y) * e;
    }
    camera.lookAt(0, 0.5, -6);

    // sign flicker
    const fl = Math.random() > 0.985 ? 0.45 + Math.random() * 0.3 : 1;
    signMat.opacity = fl * (0.97 + Math.sin(t * 2.2) * 0.03);
    halo.material.opacity = signMat.opacity;
    if (sign3d) {
      // gentle 3D sway so the depth reads
      sign3d.rotation.y = Math.sin(t * 0.35) * 0.22;
      sign3d.rotation.x = Math.sin(t * 0.21) * 0.05;
      sign3dMats[0].opacity = signMat.opacity;
      sign3dMats[1].opacity = signMat.opacity * 0.9;
    }

    // rain fall
    const rp = rainGeo.attributes.position.array;
    for (let i = 0; i < RAIN; i++) {
      rp[i * 3 + 1] -= 0.32 + (i % 7) * 0.02;
      if (rp[i * 3 + 1] < -4) rp[i * 3 + 1] = 26;
    }
    rainGeo.attributes.position.needsUpdate = true;
    dust.rotation.y = t * 0.02;

    renderer.render(scene, camera);
  }
  raf = requestAnimationFrame(loop);

  document.addEventListener('intro:done', () => {
    cancelAnimationFrame(raf);
    renderer.dispose();
  }, { once: true });
})();
